CREATE TABLE olist_sellers_dataset (
seller_id              uuid PRIMARY KEY,           -- Identificador único del vendedor dentro del marketplace de Olist
seller_zip_code_prefix text,                       -- Primeros 5 dígitos del código postal de la ubicación del vendedor, usado para geolocalización y cálculo de distancia de envío
seller_city            text,                       -- Ciudad donde está radicado el vendedor
seller_state           text                        -- Estado donde está radicado el vendedor, representado con código de 2 caracteres (ej. SP, RJ, MG)
);

CREATE TABLE product_category_name_translation (
product_category_name         text PRIMARY KEY,    -- Nombre original de la categoría en portugués, tal como aparece en olist_products_dataset. Clave de unión entre ambas tablas
product_category_name_english text                 -- Traducción al inglés del nombre de la categoría. Usar esta columna cuando el usuario consulte categorías en inglés
);
